class ComputationCache {
    private final SecureDiskCache diskCache;
    
    public ComputationCache(String cacheDir, long maxSize) throws IOException {
        this.diskCache = new SecureDiskCache(cacheDir, maxSize);
    }
    
    public <T> T computeIfAbsent(String key, ComputationFunction<T> computation) throws Exception {
        SecureDiskCache.CacheableData cached = diskCache.get(key);
        if (cached != null) {
            return extractResult(cached);
        }
        
        T result = computation.compute();
        
        SecureDiskCache.CacheableData cacheData = new SecureDiskCache.CacheableData("COMPUTATION_RESULT");
        cacheData.put("result", serializeResult(result));
        cacheData.put("computedAt", System.currentTimeMillis());
        
        diskCache.put(key, cacheData);
        
        return result;
    }
    
    public void invalidate(String key) throws IOException {
        diskCache.remove(key);
    }
    
    public void clear() throws IOException {
        diskCache.clear();
    }
    
    @SuppressWarnings("unchecked")
    private <T> T extractResult(SecureDiskCache.CacheableData data) {
        Object result = data.get("result");
        return (T) result;
    }
    
    private Object serializeResult(Object result) {
        if (result == null) return null;
        if (result instanceof String || 
            result instanceof Number || 
            result instanceof Boolean ||
            result instanceof Map ||
            result instanceof List) {
            return result;
        }
        return result.toString();
    }
    
    @FunctionalInterface
    public interface ComputationFunction<T> {
        T compute() throws Exception;
    }
}

